## 6. Create Browse Recipes page (static SSR)

Create `Components/Pages/Recipes.razor`:
```razor
@page "/recipes"
@page "/recipes/{Category}"
@inject RecipeShare.Services.RecipeService RecipeService

<PageTitle>@(Category is not null ? $"{Category} Recipes" : "All Recipes") - RecipeShare</PageTitle>

<nav aria-label="breadcrumb" class="mb-3">
    <ol class="breadcrumb">
        <li class="breadcrumb-item"><a href="/">Home</a></li>
        @if (Category is not null)
        {
            <li class="breadcrumb-item"><a href="/recipes">Recipes</a></li>
            <li class="breadcrumb-item active">@Category</li>
        }
        else
        {
            <li class="breadcrumb-item active">Recipes</li>
        }
    </ol>
</nav>

@if (Category is not null)
{
    <h1>@Category Recipes</h1>
}
else
{
    <h1>All Recipes</h1>
    <div class="mb-4">
        <span class="me-2">Filter by category:</span>
        @foreach (var cat in RecipeService.GetCategories())
        {
            <a href="/recipes/@cat" class="btn btn-sm btn-outline-secondary me-1 mb-1">@cat</a>
        }
    </div>
}

<div class="row row-cols-1 row-cols-md-2 row-cols-lg-3 g-4">
    @foreach (var recipe in recipes)
    {
        <div class="col">
            <div class="card h-100 shadow-sm">
                <div class="card-body">
                    <div class="display-4 text-center mb-3">@recipe.ImagePlaceholder</div>
                    <h5 class="card-title">@recipe.Title</h5>
                    <p class="card-text text-muted">@recipe.Description</p>
                    <div class="d-flex justify-content-between align-items-center">
                        <span class="badge bg-secondary">@recipe.Category</span>
                        <span class="text-warning">
                            @for (int i = 1; i <= 5; i++)
                            {
                                @(i <= (int)Math.Round(recipe.AverageRating) ? "★" : "☆")
                            }
                            <small class="text-muted">(@recipe.TotalRatings)</small>
                        </span>
                    </div>
                </div>
                <div class="card-footer bg-transparent border-0">
                    <a href="/recipe/@recipe.Id" class="btn btn-primary w-100">View Recipe</a>
                </div>
            </div>
        </div>
    }
</div>

@if (!recipes.Any())
{
    <div class="alert alert-info">No recipes found in this category.</div>
}

@code {
    [Parameter]
    public string? Category { get; set; }

    private List<RecipeShare.Models.Recipe> recipes = new();

    protected override void OnInitialized()
    {
        recipes = Category is not null
            ? RecipeService.GetRecipesByCategory(Category)
            : RecipeService.GetAllRecipes();
    }
}
```

## 7. Create the StarRating interactive component

Create `Components/StarRating.razor`:
```razor
@rendermode InteractiveServer

<div class="d-inline-block">
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <span class="star @(star <= (hoveredStar > 0 ? hoveredStar : selectedStar) ? "filled" : "")"
              role="button"
              @onmouseover="() => hoveredStar = star"
              @onmouseout="() => hoveredStar = 0"
              @onclick="() => SelectStar(star)">
            @(star <= (hoveredStar > 0 ? hoveredStar : selectedStar) ? "★" : "☆")
        </span>
    }
    @if (submitted)
    {
        <span class="text-success ms-2">✓ Thanks!</span>
    }
</div>

@code {
    [Parameter]
    public int RecipeId { get; set; }

    [Parameter]
    public EventCallback<int> OnRated { get; set; }

    private int selectedStar;
    private int hoveredStar;
    private bool submitted;

    private async Task SelectStar(int star)
    {
        if (submitted) return;
        selectedStar = star;
        submitted = true;
        await OnRated.InvokeAsync(star);
    }
}
```

Create `Components/StarRating.razor.css`:
```css
.star {
    font-size: 1.5rem;
    cursor: pointer;
    color: #ccc;
    transition: color 0.15s;
    user-select: none;
}

.star.filled {
    color: #ffc107;
}

.star:hover {
    transform: scale(1.2);
}
```

