```razor
@rendermode InteractiveServer

<div class="d-inline-block">
    @for (int i = 1; i <= 5; i++)
    {
        var star = i;
        <span class="star @(star <= (hoveredStar > 0 ? hoveredStar : selectedStar) ? "filled" : "")"
              role="button"
              @onmouseover="() => hoveredStar = star"
              @onmouseout="() => hoveredStar = 0"
              @onclick="() => SelectStar(star)">
            @(star <= (hoveredStar > 0 ? hoveredStar : selectedStar) ? "★" : "☆")
        </span>
    }
    @if (submitted)
    {
        <span class="text-success ms-2">✓ Thanks!</span>
    }
</div>

@code {
    [Parameter]
    public int RecipeId { get; set; }

    [Parameter]
    public EventCallback<int> OnRated { get; set; }

    private int selectedStar;
    private int hoveredStar;
    private bool submitted;

    private async Task SelectStar(int star)
    {
        if (submitted) return;
        selectedStar = star;
        submitted = true;
        await OnRated.InvokeAsync(star);
    }
}
